import React from 'react';
import { useCurrentFrame, useVideoConfig } from 'remotion';
import { PlacementBox, resolveSize } from '../../../lib/canvas';
import { seededRandom } from '../../../lib/random';
import { rgbGlitchTextSchema, type RgbGlitchTextProps } from './schema';

export { rgbGlitchTextSchema, type RgbGlitchTextProps };

/**
 * RGB channel-split text — a red and a cyan copy ride just off the white
 * center, with periodic glitch bursts that kick the split wider. The burst
 * jitter is a pure function of a seeded PRNG keyed by the frame bucket, so it
 * renders identically every time (§1). High-energy by design; the baseline
 * split is restrained so the bursts read as punctuation.
 *
 * @example
 * <RgbGlitchText text="GLITCH" />
 */
export const RgbGlitchText: React.FC<RgbGlitchTextProps> = ({
  text, delay, baseSplit, intensity, glitchPeriod, glitchDuration, seed,
  color, redColor, cyanColor, fontSize, size, fontFamily, fontWeight, letterSpacing, align, placement,
}) => {
  const frame = useCurrentFrame();
  const { width, height } = useVideoConfig();
  const local = Math.max(0, frame - delay);
  const resolvedFontSize = size ? resolveSize(size, { width, height }) : fontSize;

  const inBurst = local % glitchPeriod < glitchDuration;
  const bucket = Math.floor(local / 2);
  const rand = seededRandom(seed + bucket * 7919);
  const burst = inBurst ? rand() * 2 - 1 : 0;
  const dx = baseSplit + burst * intensity;
  const dy = inBurst ? (rand() * 2 - 1) * intensity * 0.4 : 0;

  const layer = (tint: string, ox: number, oy: number): React.CSSProperties => ({
    position: 'absolute',
    inset: 0,
    color: tint,
    transform: `translate(${ox}px, ${oy}px)`,
    mixBlendMode: 'screen',
  });

  const base: React.CSSProperties = {
    fontFamily, fontSize: resolvedFontSize, fontWeight, letterSpacing, textAlign: align, whiteSpace: 'pre',
  };

  return (
    <PlacementBox placement={placement}>
      <div style={{ position: 'relative', ...base }}>
        <div style={layer(redColor, -dx, -dy)}>{text}</div>
        <div style={layer(cyanColor, dx, dy)}>{text}</div>
        <div style={{ position: 'relative', color }}>{text}</div>
      </div>
    </PlacementBox>
  );
};

import { z } from 'zod';
import { placementSchema, sizeRoleSchema } from '../../../lib/canvas-schemas';

/** Zod schema for {@link RgbGlitchText} props. */
export const rgbGlitchTextSchema = z.object({
  /** Discriminator literal — matches this entry's registry slug. Auto-populated when omitted. */
  kind: z.literal('rgb-glitch-text').default('rgb-glitch-text'),
  /** The text to glitch. */
  text: z.string().default('GLITCH'),
  /** Frames before the effect starts. */
  delay: z.number().int().min(0).default(0),
  /** Constant baseline channel split in px (the always-on chromatic edge). */
  baseSplit: z.number().default(2),
  /** Peak extra split in px during a glitch burst. */
  intensity: z.number().default(10),
  /** Frames between glitch bursts. */
  glitchPeriod: z.number().int().min(1).default(48),
  /** Frames a glitch burst lasts. */
  glitchDuration: z.number().int().min(1).default(8),
  /** Seed for the (deterministic) burst jitter. */
  seed: z.number().int().default(7),
  /** Base (center) text color. Defaults to `--onda-text`. */
  color: z.string().default('var(--onda-text, #F2F2F4)'),
  /** Red-channel copy color. */
  redColor: z.string().default('#FF4D6D'),
  /** Cyan-channel copy color. */
  cyanColor: z.string().default('#4DE2FF'),
  /** Pixels. Wins over `size` if both are passed. */
  fontSize: z.number().default(120),
  /** Semantic typography role — canvas-aware pixels. */
  size: sizeRoleSchema.optional(),
  /** Font family. */
  fontFamily: z.string().default('var(--onda-font-display, "Clash Display", sans-serif)'),
  /** Font weight. */
  fontWeight: z.number().default(600),
  /** CSS letter-spacing. */
  letterSpacing: z.string().default('-0.02em'),
  /** Text alignment. */
  align: z.enum(['left', 'center', 'right']).default('center'),
  /** Where on the canvas this sits. */
  placement: placementSchema.optional(),
});

/** Inferred props for {@link RgbGlitchText}. */
export type RgbGlitchTextProps = z.infer<typeof rgbGlitchTextSchema>;
